package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.io.OutputStreamWriter;
import java.lang.reflect.Method;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

public class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testPrint_FileCharset_success() throws IOException {
        File mockFile = mock(File.class);
        Charset charset = Charset.forName("UTF-8");

        // Mock FileOutputStream and OutputStreamWriter to avoid actual file IO
        try (var mockedFOS = Mockito.mockStatic(FileOutputStream.class);
             var mockedOSW = Mockito.mockConstruction(OutputStreamWriter.class,
                (mock, context) -> {
                    // no special behavior needed
                })) {

            mockedFOS.when(() -> new FileOutputStream(mockFile)).thenReturn(mock(FileOutputStream.class));

            CSVPrinter printer = csvFormat.print(mockFile, charset);
            assertNotNull(printer);
        }
    }

    @Test
    public void testPrint_FileCharset_nullCharset() {
        File file = new File("test.csv");
        assertThrows(NullPointerException.class, () -> csvFormat.print(file, null));
    }

    @Test
    public void testPrint_FileCharset_invalidFile() {
        File file = new File("/invalid/path/to/file.csv");
        Charset charset = Charset.defaultCharset();
        // This will throw IOException because file path is invalid or not writable
        assertThrows(IOException.class, () -> csvFormat.print(file, charset));
    }

    @Test
    public void testPrint_PrivatePrintMethod() throws Exception {
        // Use reflection to invoke private print method:
        // private void print(final Object object, final CharSequence value, final int offset, final int len,
        // final Appendable out, final boolean newRecord)
        Method printMethod = CSVFormat.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class,
                int.class, Appendable.class, boolean.class);
        printMethod.setAccessible(true);

        Appendable mockAppendable = mock(Appendable.class);

        // Call with newRecord = true, offset and len within bounds
        printMethod.invoke(csvFormat, "value", "value", 0, 5, mockAppendable, true);
        verify(mockAppendable, atLeastOnce()).append(any(CharSequence.class));

        // Call with newRecord = false, offset and len within bounds
        printMethod.invoke(csvFormat, "value", "value", 0, 5, mockAppendable, false);
        verify(mockAppendable, atLeastOnce()).append(any(CharSequence.class));
    }

    @Test
    public void testPrint_PrivatePrintAndEscapeMethod() throws Exception {
        Method printAndEscape = CSVFormat.class.getDeclaredMethod("printAndEscape", CharSequence.class, int.class, int.class,
                Appendable.class);
        printAndEscape.setAccessible(true);

        Appendable mockAppendable = mock(Appendable.class);

        // Normal call
        printAndEscape.invoke(csvFormat, "escapeValue", 0, 11, mockAppendable);
        verify(mockAppendable, atLeastOnce()).append(any(CharSequence.class));
    }

    @Test
    public void testPrint_PrivatePrintAndQuoteMethod() throws Exception {
        Method printAndQuote = CSVFormat.class.getDeclaredMethod("printAndQuote", Object.class, CharSequence.class, int.class,
                int.class, Appendable.class, boolean.class);
        printAndQuote.setAccessible(true);

        Appendable mockAppendable = mock(Appendable.class);

        // Call with newRecord = true
        printAndQuote.invoke(csvFormat, "object", "quoteValue", 0, 10, mockAppendable, true);
        verify(mockAppendable, atLeastOnce()).append(any(CharSequence.class));

        // Call with newRecord = false
        printAndQuote.invoke(csvFormat, "object", "quoteValue", 0, 10, mockAppendable, false);
        verify(mockAppendable, atLeast(2)).append(any(CharSequence.class));
    }
}
